const axios = require('axios');

const residentialRegex = /(apartment|house|villa|penthouse|condo|condominium|townhouse|bungalow|cottage|studio|flat|duplex|triplex|maisonette|loft|chalet|cabin|manor|mansion|residential)/i;

const propertyType = $('AI Agent').first().json.output.property_type|| "";

if($input.first().json.passed == false)
{
   return [{ json: { passed: false, reason: $input.first().json.reason, propertyType, routedTo: "" } }];
}

const safe_text = $input.first().json.safe_text;

let targetUrl = "http://commercial_team:8000/listing"; 
if (residentialRegex.test(propertyType)) {
targetUrl = "https://residential_team:8000/listing";
}

// 5. Send the payload to the respective endpoint
try {
  await axios.post(targetUrl, safe_text);
} catch (error) {
  // If the request fails, attach the error log to the node output for debugging
    return [{ json: { success: false, error: error.message, propertyType, routedTo: targetUrl } }];
  }

  // Return the final data payload along with routing details
  return [
    {
      json: {
        success: true,
        routedTo: targetUrl,
        propertyType: propertyType,
        safe_text: safe_text
      }
    }
  ];
